class Solution:
    def maxSumDivThree(self, nums):
        # Brute-force subset enumeration via recursion (only feasible for small n).
        # For stress correctness checking the generator keeps n small.
        from functools import lru_cache
        n = len(nums)
        @lru_cache(maxsize=None)
        def best(i, rem):
            if i == n:
                return 0 if rem == 0 else float('-inf')
            take = nums[i] + best(i + 1, (rem + nums[i]) % 3)
            skip = best(i + 1, rem)
            return max(take, skip)
        result = best(0, 0)
        return result if result != float('-inf') else 0

