class Solution:
    def maxSumDivThree(self, nums):
        # dp[r] = max sum reachable with remainder r; -1 means unreachable
        dp = [-1, -1, -1]
        dp[0] = 0
        for num in nums:
            new_dp = dp[:]
            r = num % 3
            for prev_r in range(3):
                if dp[prev_r] == -1:
                    continue
                new_r = (prev_r + r) % 3
                candidate = dp[prev_r] + num
                if new_dp[new_r] < candidate:
                    new_dp[new_r] = candidate
            dp = new_dp
        return dp[0]

