var maxSumDivThree = function(nums) {
    // dp[r] = max sum with remainder r; -1 means unreachable
    const dp = [-1, -1, -1];
    dp[0] = 0;
    for (const num of nums) {
        const newDp = dp.slice();
        const r = num % 3;
        for (let prevR = 0; prevR < 3; prevR++) {
            if (dp[prevR] === -1) continue;
            const newR = (prevR + r) % 3;
            const candidate = dp[prevR] + num;
            if (newDp[newR] < candidate) newDp[newR] = candidate;
        }
        dp[0] = newDp[0]; dp[1] = newDp[1]; dp[2] = newDp[2];
    }
    return dp[0] === -1 ? 0 : dp[0];
};
